SELECT cl.id, cl.task_id AS taskId, cl.task_name AS taskName,
       cl.start_time AS startTime, cl.end_time AS endTime,
       cl.status, cl.crawled_count AS crawledCount,
       cl.error_message AS errorMessage, cl.retry_count AS retryCount,
       cl.executor_id AS executorId, cl.created_at AS createdAt
FROM crawl_task_logs cl


        AND cl.task_id = #{taskId}


        AND cl.status = #{status}


ORDER BY cl.id DESC
LIMIT #{offset}, #{limit}

